#include <bits/stdc++.h>
using namespace std;

vector<int> solve(int N) {
    vector<int> denominations = {2000, 500, 200, 100, 50, 20, 10, 5, 2, 1};
    vector<int> result;

    // Greedy approach - start with largest denomination
    for(int coin : denominations) {
        // While we can use current denomination
        while(N >= coin) {
            result.push_back(coin);
            N -= coin;
        }
    }

    return result;
}

int main() {
    int N;
    cin >> N;

    vector<int> result = solve(N);

    // Print denominations used
    for(int coin : result) {
        cout << coin << " ";
    }
    cout << endl;

    return 0;
}
